export async function GET() {
const res = await fetch(
`${process.env.NEXT_PUBLIC_API_URL}/forecast`,
{ cache: "no-store" }
);


if (!res.ok) {
return new Response(
JSON.stringify({ error: "Failed to fetch forecast" }),
{ status: 500 }
);
}


const data = await res.json();
return Response.json(data);
}